onClick:
{{
  (function() {
    if (!sel_item_type.selectedOptionValue) {
      showAlert('Select an item type', 'warning');
      return;
    }
    if (!sel_make.selectedOptionValue) {
      showAlert('Select a make', 'warning');
      return;
    }
    if (!sel_model.selectedOptionValue) {
      showAlert('Select a model', 'warning');
      return;
    }
    var qty = Number(inp_qty.text) || 1;
    var serials = qty === 1 ? [inp_serial.text || ''] : new Array(qty).fill('');
    storeValue('pendingItemType', sel_item_type.selectedOptionValue);
    storeValue('pendingMake', sel_make.selectedOptionValue);
    storeValue('pendingModel', sel_model.selectedOptionValue);
    storeValue('pendingDataBearing', sw_data_bearing.isSwitchedOn);
    storeValue('pendingSerials', JSON.stringify(serials));
    storeValue('pendingQty', qty);
    var refs = [];
    function getNextRef(remaining) {
      if (remaining === 0) {
        storeValue('pendingAssetRefs', JSON.stringify(refs)).then(function() {
          showAlert('Refs: ' + appsmith.store.pendingAssetRefs + ' | Serials: ' + appsmith.store.pendingSerials, 'info');
          qry_asset_insert.run(
            function() {
              qry_booked_assets.run();
              showAlert(qry_asset_insert.data.length + ' asset(s) added', 'success');
              resetWidget('inp_serial');
              resetWidget('inp_asset_tag');
              resetWidget('inp_qty');
              resetWidget('sel_item_type');
              resetWidget('sel_make');
              resetWidget('sel_model');
              resetWidget('sw_data_bearing');
            },
            function() {
              showAlert('Failed to add asset(s) — check all fields', 'error');
            }
          );
        });
        return;
      }
      qry_next_asset_ref.run(
        function() {
          refs.push(qry_next_asset_ref.data[0]?.asset_ref);
          getNextRef(remaining - 1);
        },
        function() {
          showAlert('Failed to generate asset reference', 'error');
        }
      );
    }
    getNextRef(qty);
  })()
}}
